import{_ as a,o as i,c as s,ai as t}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"语音唤醒","description":"","frontmatter":{"read_when":["更改语音唤醒词行为或默认值","添加需要唤醒词同步的新节点平台"],"summary":"全局语音唤醒词（Gateway 网关拥有）及其如何跨节点同步","title":"语音唤醒","x-i18n":{"generated_at":"2026-02-03T07:51:10Z","model":"claude-opus-4-5","provider":"pi","source_hash":"eb34f52dfcdc3fc1ae088ae1f621f245546d3cf388299fbeea62face61788c37","source_path":"nodes/voicewake.md","workflow":15}},"headers":[],"relativePath":"zh-CN/nodes/voicewake.md","filePath":"zh-CN/nodes/voicewake.md","lastUpdated":1771906665000}'),o={name:"zh-CN/nodes/voicewake.md"};function l(d,e,n,r,h,c){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="语音唤醒-全局唤醒词" tabindex="-1"><a class="header-anchor" href="#语音唤醒-全局唤醒词">#</a> 语音唤醒（全局唤醒词）</h1><p>OpenSoul 将<strong>唤醒词作为单一全局列表</strong>，由 <strong>Gateway 网关</strong>拥有。</p><ul><li><strong>没有</strong>每节点的自定义唤醒词。</li><li><strong>任何节点/应用 UI 都可以编辑</strong>列表；更改由 Gateway 网关持久化并广播给所有人。</li><li>每个设备仍保留自己的<strong>语音唤醒启用/禁用</strong>开关（本地用户体验 + 权限不同）。</li></ul><h2 id="存储-gateway-网关主机" tabindex="-1"><a class="header-anchor" href="#存储-gateway-网关主机">#</a> 存储（Gateway 网关主机）</h2><p>唤醒词存储在 Gateway 网关机器上：</p><ul><li><code>~/.opensoul/settings/voicewake.json</code></li></ul><p>结构：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;triggers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opensoul&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;computer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;updatedAtMs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1730000000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="协议" tabindex="-1"><a class="header-anchor" href="#协议">#</a> 协议</h2><h3 id="方法" tabindex="-1"><a class="header-anchor" href="#方法">#</a> 方法</h3><ul><li><code>voicewake.get</code> → <code>{ triggers: string[] }</code></li><li><code>voicewake.set</code>，参数 <code>{ triggers: string[] }</code> → <code>{ triggers: string[] }</code></li></ul><p>注意事项：</p><ul><li>触发词会被规范化（修剪空格、删除空值）。空列表回退到默认值。</li><li>为安全起见会强制执行限制（数量/长度上限）。</li></ul><h3 id="事件" tabindex="-1"><a class="header-anchor" href="#事件">#</a> 事件</h3><ul><li><code>voicewake.changed</code> 载荷 <code>{ triggers: string[] }</code></li></ul><p>接收者：</p><ul><li>所有 WebSocket 客户端（macOS 应用、WebChat 等）</li><li>所有已连接的节点（iOS/Android），以及节点连接时作为初始&quot;当前状态&quot;推送。</li></ul><h2 id="客户端行为" tabindex="-1"><a class="header-anchor" href="#客户端行为">#</a> 客户端行为</h2><h3 id="macos-应用" tabindex="-1"><a class="header-anchor" href="#macos-应用">#</a> macOS 应用</h3><ul><li>使用全局列表来控制 <code>VoiceWakeRuntime</code> 触发器。</li><li>在语音唤醒设置中编辑&quot;触发词&quot;会调用 <code>voicewake.set</code>，然后依赖广播保持其他客户端同步。</li></ul><h3 id="ios-节点" tabindex="-1"><a class="header-anchor" href="#ios-节点">#</a> iOS 节点</h3><ul><li>使用全局列表进行 <code>VoiceWakeManager</code> 触发检测。</li><li>在设置中编辑唤醒词会调用 <code>voicewake.set</code>（通过 Gateway 网关 WS），同时保持本地唤醒词检测的响应性。</li></ul><h3 id="android-节点" tabindex="-1"><a class="header-anchor" href="#android-节点">#</a> Android 节点</h3><ul><li>在设置中暴露唤醒词编辑器。</li><li>通过 Gateway 网关 WS 调用 <code>voicewake.set</code>，使编辑在所有地方同步。</li></ul>',24)])])}const u=a(o,[["render",l]]);export{k as __pageData,u as default};
